def validate(args, output):
    n = args[0]
    if not isinstance(output, list):
        return False
    seen = set()
    for s in output:
        if not isinstance(s, str) or len(s) != n:
            return False
        if any(c not in '01' for c in s):
            return False
        if '00' in s:
            return False
        if s in seen:
            return False
        seen.add(s)
    # completeness: count via DP (Fibonacci-like)
    if n == 0:
        return len(output) == 1
    dp = [0] * (n + 1)
    dp[0] = 1
    if n >= 1:
        dp[1] = 2
    for i in range(2, n + 1):
        dp[i] = dp[i-1] + dp[i-2]
    return len(output) == dp[n]

