function validate(args, output) {
    const n = args[0];
    if (!Array.isArray(output)) return false;
    const seen = new Set();
    for (const s of output) {
        if (typeof s !== 'string' || s.length !== n) return false;
        if (!/^[01]+$/.test(s)) return false;
        if (s.includes('00')) return false;
        if (seen.has(s)) return false;
        seen.add(s);
    }
    if (n === 0) return output.length === 1;
    const dp = new Array(n + 1).fill(0);
    dp[0] = 1;
    if (n >= 1) dp[1] = 2;
    for (let i = 2; i <= n; i++) dp[i] = dp[i-1] + dp[i-2];
    return output.length === dp[n];
}

