class Solution:
    def validStrings(self, n: int):
        res = []
        def bt(path, prev):
            if len(path) == n:
                res.append(''.join(path))
                return
            if prev != '0':
                path.append('0')
                bt(path, '0')
                path.pop()
            path.append('1')
            bt(path, '1')
            path.pop()
        bt([], '1')
        return sorted(res)

