class Solution:
    def validStrings(self, n: int):
        res = []
        def bt(s, prev):
            if len(s) == n:
                res.append(s)
                return
            if prev != '0':
                bt(s + '0', '0')
            bt(s + '1', '1')
        bt('', '1')
        return sorted(res)

